#' Penalized Cox Regression Guide
#'
#' An interactive guide to penalized Cox regression methods available in 
#' ClinicoPath. Helps clinicians, pathologists, radiologists, and oncologists 
#' choose the right analysis for their data and research question. No data or 
#' variables required.
#' 
#'
#' @examples
#' \donttest{
#' # Simply open the guide - no data needed
#' lassointro()
#'}
#' @param showOverview Show overview of all penalized Cox regression methods
#' @param showDecisionGuide Show decision flowchart for choosing the right
#'   method
#' @param showClinicalScenarios Show worked examples for pathology, radiology,
#'   and oncology
#' @param showAssumptions Show key assumptions, common pitfalls, and how to
#'   avoid them
#' @param showGlossary Show glossary of technical terms in plain language
#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$overview} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$decisionGuide} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$clinicalScenarios} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$assumptions} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$glossary} \tab \tab \tab \tab \tab a html \cr
#' }
#'
#' @export
lassointro <- function(
    showOverview = TRUE,
    showDecisionGuide = TRUE,
    showClinicalScenarios = FALSE,
    showAssumptions = FALSE,
    showGlossary = FALSE) {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("lassointro requires jmvcore to be installed (restart may be required)")


    options <- lassointroOptions$new(
        showOverview = showOverview,
        showDecisionGuide = showDecisionGuide,
        showClinicalScenarios = showClinicalScenarios,
        showAssumptions = showAssumptions,
        showGlossary = showGlossary)

    analysis <- lassointroClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

